import { config } from "../../config/index.js";
import type { ItemCategory, ItemDefinition } from "../../schemas/entities/index.js";
import {
  chebyshevDistance,
  getTile,
  inBounds,
  isWalkableTile,
  type TileGrid,
} from "../map/index.js";
import {
  allocateEntityId,
  type EngineLogEventDataByType,
  type EntityId,
  type GameState,
  type GroundItemEntityInstance,
  type InventorySlot,
  type PlayerItemStack,
