export const removeFromInventory = (
  state: GameState,
  itemInstanceId: string,
  quantity = 1,
): InventoryOperationResult => {
  const slotIndex = findInventorySlotIndex(state.player.inventory, itemInstanceId);

  if (slotIndex === null) {
    return {
      illegal: true,
      reason: `Item ${itemInstanceId} is not in your pack.`,
    };
  }

  const slot = readInventorySlot(state.player.inventory, slotIndex, itemInstanceId);

  if ("illegal" in slot) {
    return slot;
  }

  if (quantity < 1 || quantity > slot.quantity) {
    return {
      illegal: true,
      reason: `Cannot remove ${quantity} from a stack of ${slot.quantity}.`,
    };
  }

  const inventory = [...state.player.inventory];

  if (quantity === slot.quantity) {
    inventory[slotIndex] = null;
  } else {
    inventory[slotIndex] = {
      itemInstanceId: slot.itemInstanceId,
      definition: slot.definition,
      quantity: slot.quantity - quantity,
      identified: slot.identified,
    };
  }

  return {
    state: withInventory(state, inventory),
    events: [],
  };
};

export const splitInventoryStack = (
  state: GameState,
  itemInstanceId: string,
  quantity: number,
): InventoryOperationResult => {
  const slotIndex = findInventorySlotIndex(state.player.inventory, itemInstanceId);

  if (slotIndex === null) {
    return {
      illegal: true,
      reason: `Item ${itemInstanceId} is not in your pack.`,
    };
  }

  const slot = readInventorySlot(state.player.inventory, slotIndex, itemInstanceId);

  if ("illegal" in slot) {
    return slot;
  }

  if (quantity < 1 || quantity >= slot.quantity) {
    return {
      illegal: true,
      reason: `Cannot split ${quantity} from a stack of ${slot.quantity}.`,
    };
  }

  const emptyIndex = findEmptyInventorySlotIndex(state.player.inventory);

  if (emptyIndex === null) {
    return {
      illegal: true,
      reason: FULL_INVENTORY_REASON,
    };
  }

  const inventory = [...state.player.inventory];
  inventory[slotIndex] = {
    itemInstanceId: slot.itemInstanceId,
    definition: slot.definition,
    quantity: slot.quantity - quantity,
    identified: slot.identified,
  };
  inventory[emptyIndex] = {
    itemInstanceId: `${slot.itemInstanceId}#split`,
    definition: slot.definition,
    quantity,
    identified: slot.identified,
  };

  return {
    state: withInventory(state, inventory),
    events: [],
  };
};

export const groundItemAt = (
  state: GameState,
  position: Position,
): GroundItemEntityInstance | null => {
  const items = Object.values(state.entities)
    .filter(
      (entity): entity is GroundItemEntityInstance =>
        entity.kind === "item" && samePosition(entity.position, position),
    )
    .sort((a, b) => a.id.localeCompare(b.id));

  return items[0] ?? null;
};

export const resolvePickupAction: ActionResolver<PickupAction> = (
  state,
): ActionResolverResult => {
  const groundItem = groundItemAt(state, state.player.position);

  if (groundItem === null) {
    return {
      illegal: true,
      reason: "There is nothing here to pick up.",
    };
  }

  const stack: PlayerItemStack = {
    itemInstanceId: groundItem.id,
    definition: groundItem.definition,
    quantity: groundItem.quantity,
    identified: groundItem.identified,
  };

  if (!canAddQuantityToInventory(state.player.inventory, stack.definition, stack.quantity)) {
    return {
      illegal: true,
      reason: FULL_INVENTORY_REASON,
    };
  }

  const added = addToInventory(state, stack);

  if ("illegal" in added) {
    return added;
  }

  const nextEntities = { ...added.state.entities };
  delete nextEntities[groundItem.id];

  const stacked =
    findStackSlotIndex(state.player.inventory, stack.definition.id) !== null;

  return {
    state: {
      ...added.state,
      entities: nextEntities,
    },
    events: [
      inventoryEvent(state, "item_picked_up", {
        itemInstanceId: stack.itemInstanceId,
        entityId: groundItem.id,
        definitionId: stack.definition.id,
        quantity: stack.quantity,
        stacked,
      }),
    ],
  };
};

export const dropItem = (
  state: GameState,
  itemInstanceId: string,
  quantity = 1,
): InventoryOperationResult => {
  const slotIndex = findInventorySlotIndex(state.player.inventory, itemInstanceId);

  if (slotIndex === null) {
    return {
      illegal: true,
      reason: `Item ${itemInstanceId} is not in your pack.`,
    };
  }

  const slot = readInventorySlot(state.player.inventory, slotIndex, itemInstanceId);

  if ("illegal" in slot) {
    return slot;
  }

  if (quantity < 1 || quantity > slot.quantity) {
    return {
      illegal: true,
      reason: `Cannot drop ${quantity} from a stack of ${slot.quantity}.`,
    };
  }

  const grid = gridFromState(state);

  if (grid === null) {
    return {
      illegal: true,
      reason: "The floor layout is not loaded.",
    };
  }

  const placement = findDropPlacement(state, grid, state.player.position);

  if (placement === null) {
    return {
      illegal: true,
      reason: "There is no room to drop that here.",
    };
  }

  const removed = removeFromInventory(state, itemInstanceId, quantity);

  if ("illegal" in removed) {
    return removed;
  }

  const allocation = allocateEntityId(removed.state.ids.entityCounters, "item");
  const entity: GroundItemEntityInstance = {
    id: allocation.id,
    kind: "item",
    definition: slot.definition,
    position: placement,
    currentHP: null,
    statuses: [],
    behaviorRuntime: {},
    quantity,
    identified: slot.identified,
  };

  return {
    state: {
      ...removed.state,
      ids: {
        ...removed.state.ids,
        entityCounters: allocation.entityCounters,
      },
      entities: {
        ...removed.state.entities,
        [entity.id]: entity,
      },
    },
    events: [
      inventoryEvent(state, "item_dropped", {
        itemInstanceId,
        entityId: entity.id,
        definitionId: slot.definition.id,
        quantity,
        position: placement,
      }),
    ],
  };
};

export const equipItem = (
  state: GameState,
  itemInstanceId: string,
  target?: EquipTarget,
): InventoryOperationResult => {
  const slotIndex = findInventorySlotIndex(state.player.inventory, itemInstanceId);

  if (slotIndex === null) {
    return {
      illegal: true,
      reason: `Item ${itemInstanceId} is not in your pack.`,
    };
  }

  const carried = readInventorySlot(state.player.inventory, slotIndex, itemInstanceId);

  if ("illegal" in carried) {
    return carried;
  }

  if (carried.quantity !== 1) {
    return {
      illegal: true,
      reason: "Split the stack before equipping that item.",
    };
  }

  const resolvedTarget =
    target ?? defaultEquipTarget(carried.definition, state.player.equipment.charms);

  if (resolvedTarget === null) {
    return {
      illegal: true,
      reason: `${carried.definition.kind} items cannot be equipped.`,
    };
  }

  if (!isValidEquipTarget(resolvedTarget, carried.definition)) {
    return {
      illegal: true,
      reason: `Item ${itemInstanceId} does not fit that equipment slot.`,
    };
  }

  const inventory = [...state.player.inventory];
  inventory[slotIndex] = null;

  const equipment = {
    weapon: state.player.equipment.weapon,
    armor: state.player.equipment.armor,
    charms: [...state.player.equipment.charms],
  };

  let swappedItem: PlayerItemStack | null = null;

  switch (resolvedTarget.kind) {
    case "weapon":
      swappedItem = equipment.weapon;
      equipment.weapon = carried;
      break;
    case "armor":
      swappedItem = equipment.armor;
      equipment.armor = carried;
      break;

const checkUseItemAction = (
  state: GameState,
  action: UseItemAction,
): ActionLegality => {
  if (
    !state.player.inventory.some(
      (slot) => slot?.itemInstanceId === action.itemId,
    )
  ) {
    return illegal(`item ${action.itemId} is not carried`);
  }

  if (action.target === undefined || action.target.kind === "self") {
    return LEGAL_ACTION;
  }

  if (action.target.kind === "entity") {
    return state.entities[action.target.entityId] === undefined
      ? illegal(`target entity ${action.target.entityId} does not exist`)
      : LEGAL_ACTION;
  }

  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  return inBounds(grid, action.target.cell)
    ? LEGAL_ACTION
    : illegal(
        `target cell (${action.target.cell.x}, ${action.target.cell.y}) is outside the map`,
      );
};

const checkPickupAction = (state: GameState): ActionLegality => {
  if (!state.player.inventory.some((slot) => slot === null)) {
    return illegal("inventory is full");
  }

  return sortedEntities(state).some(
    (entity) =>
      entity.kind === "item" &&
      samePosition(entity.position, state.player.position),
  )
    ? LEGAL_ACTION
    : illegal("there is no item here to pick up");
};

const checkTalkAction = (
  state: GameState,
  action: TalkAction,
): ActionLegality => {
  const npc = state.entities[action.npcId];

  if (npc === undefined) {
    return illegal(`npc ${action.npcId} does not exist`);
  }

  if (npc.kind !== "npc") {
    return illegal(`target ${action.npcId} is not an npc`);
  }

  if (!isAdjacentToPlayer(state, npc.position)) {
    return illegal(`npc ${action.npcId} is not adjacent`);
  }

  return LEGAL_ACTION;
};

const checkDescendAction = (state: GameState): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  if (!inBounds(grid, state.player.position)) {
    return illegal(
      `player position (${state.player.position.x}, ${state.player.position.y}) is outside the map`,
    );
  }

  const tile = getTile(grid, state.player.position);

  return tile.terrain === Terrain.StairsDown
    ? LEGAL_ACTION
    : illegal("player is not standing on stairs down");
};

const checkInspectAction = (
  state: GameState,
  action: InspectAction,
): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  return inBounds(grid, action.cell)
    ? LEGAL_ACTION
    : illegal(`inspect cell (${action.cell.x}, ${action.cell.y}) is outside the map`);
};

const availableInspectActions = (state: GameState): readonly InspectAction[] => {
  const grid = gridFromState(state);

  if (grid === null) {
    return [];
  }

  const actions: InspectAction[] = [];

  for (let y = 0; y < grid.height; y += 1) {
    for (let x = 0; x < grid.width; x += 1) {
      actions.push({
        kind: "inspect",
        cell: { x, y },
      });
    }
  }

  return actions;
};

const carriedItems = (inventory: readonly InventorySlot[]) =>
  inventory.filter((slot) => slot !== null);

const pushIfLegal = (
  actions: PlayerAction[],
  state: GameState,
  action: PlayerAction,
): void => {
  if (isActionLegal(checkActionLegality(state, action))) {
    actions.push(action);
  }
};

const sortedEntities = (state: GameState): readonly EntityInstance[] =>
  Object.values(state.entities).sort((a, b) => a.id.localeCompare(b.id));

const isAdjacentToPlayer = (state: GameState, position: Position): boolean =>
  chebyshevDistance(state.player.position, position) <= 1;

const samePosition = (a: Position, b: Position): boolean =>
  a.x === b.x && a.y === b.y;

const offsetForDirection = (direction: MoveDirection): Position => {
  const entry = MOVE_DIRECTIONS.find((candidate) => candidate.direction === direction);

  if (entry === undefined) {
    throw new RangeError(`unknown move direction: ${direction}`);
  }

  return entry.offset;
};

const isTileGridRecord = (
  value: SerializableRecord | null,
): value is SerializableRecord => {
  if (value === null) {
    return false;
  }

  const record = value as {
    readonly kind?: unknown;
    readonly width?: unknown;
    readonly height?: unknown;
    readonly tiles?: unknown;
  };

  return (
    record.kind === "tile-grid" &&
    Number.isSafeInteger(record.width) &&
    Number.isSafeInteger(record.height) &&
    Array.isArray(record.tiles)
  );
};

