const withEffectIndex = (
  events: readonly TurnEvent[],
  effectIndex: number
): readonly TurnEvent[] =>
  events.map((event) => {
    if (event.type !== "effect_rejected") {
      return event;
    }

    return {
      ...event,
      data: {
        ...event.data,
        effectIndex
      }
    };
  });

