  state: GameState,
  attackerId: CombatActorId,
  targetCell: Position,
  options: BoltAttackOptions = {},
): ActionResolverResult => {
  const attacker = combatActor(state, attackerId);

  if (attacker === null) {
    return {
      illegal: true,
      reason: `attacker ${attackerId} is not a combat actor`,
    };
  }

  const grid = gridFromState(state);
  if (grid === null) {
    return {
      illegal: true,
      reason: "floor geometry is not loaded",
    };
  }

  if (!inBounds(grid, targetCell)) {
    return {
      illegal: true,
      reason: `bolt target cell (${targetCell.x}, ${targetCell.y}) is outside the map`,
    };
  }

  const range =
    options.range ?? bounds.effectVocabulary.targetingShapes.boltRangeTiles.max;
  const rangeBounds = bounds.effectVocabulary.targetingShapes.boltRangeTiles;

  if (
    !Number.isSafeInteger(range) ||
    range < rangeBounds.min ||
    range > rangeBounds.max
  ) {
    return {
      illegal: true,
      reason: `bolt range must be ${rangeBounds.min}-${rangeBounds.max}`,
    };
  }

  const target = findBoltTarget(state, grid, attacker, targetCell, range);

  if (target.status === "miss") {
    return {
      state,
      events: [
        combatEvent(state, "attack_missed", {
          actorId: attacker.id,
          defenderId: null,
          attackerAttack: null,
          defenderDefense: null,
          hitRoll: null,
          hitChancePercent: config.combatMath.hitChancePercent,
          reason: target.reason,
        }),
      ],
    };
  }

  return resolveAttackRoll(state, attacker, target.actor);
};

export const resolveAttackAction: ActionResolver<AttackAction> = (
  state,
  action,
): ActionResolverResult => resolveAttack(state, "player", action.targetId);

export const registerCombatActionResolver = (): (() => void) =>
  registerActionResolver("attack", resolveAttackAction);

export const unregisterCombatActionResolver = registerCombatActionResolver();

export const registerLootDropHook = (hook: LootDropHook): (() => void) => {
  const previous = lootDropHook;
  lootDropHook = hook;

  return () => {
    if (lootDropHook === hook) {
      lootDropHook = previous;
    }
  };
};

const resolveAttackRoll = (
  state: GameState,
  attacker: CombatActor,
  defender: CombatActor,
): ActionResolverResult => {
  const attackerStats = deriveCombatStats(state, attacker.id);
  const defenderStats = deriveCombatStats(state, defender.id);

  if (attackerStats === null || defenderStats === null) {
    return {
      illegal: true,
      reason: "combat stats could not be derived",
    };
  }

  const rngContext = combatRngContextFor(state);
  const hitRoll = rollInt(rngContext, HIT_ROLL_MIN, HIT_ROLL_MAX);

  if (hitRoll > config.combatMath.hitChancePercent) {
    return {
      state: withCombatRngCursor(state, rngContext),
      events: [
        combatEvent(state, "attack_missed", {
          actorId: attacker.id,
          defenderId: defender.id,
          attackerAttack: attackerStats.attack,
          defenderDefense: defenderStats.defense,
          hitRoll,
          hitChancePercent: config.combatMath.hitChancePercent,
          reason: "hit_roll",
        }),
      ],
    };
  }

  const varianceMultiplier = rollVarianceMultiplier(rngContext);
  const baseDamage = calculateBaseDamage(
    attackerStats.attack,
    defenderStats.defense,
  );
  const damage = Math.max(
    config.combatMath.minimumDamage,
    Math.round(baseDamage * varianceMultiplier),
  );
  const defenderHpAfter = Math.max(0, defender.hp - damage);
  const damagedState = withActorHp(
    withCombatRngCursor(state, rngContext),
    defender,
    defenderHpAfter,
  );
  const events: TurnEvent[] = [
    combatEvent(state, "attack_hit", {
      actorId: attacker.id,
      defenderId: defender.id,
      attackerAttack: attackerStats.attack,
      defenderDefense: defenderStats.defense,
      baseDamage,
      damage,
      hitRoll,
      hitChancePercent: config.combatMath.hitChancePercent,
      varianceMultiplier,
      defenderHpBefore: defender.hp,
      defenderHpAfter,
    }),
  ];

  if (defenderHpAfter > 0) {
    return {
      state: damagedState,
      events,
    };
  }

  const deathResult = applyDeath(damagedState, defender.id, {
    attribution: {
      kind: "killer",
      killerId: attacker.id,
    },
  });

  return {
    state: deathResult.state,
    events: [...events, ...deathResult.events],
  };
};

const playerBaseStats = (state: GameState): CombatStats => {
  const attackGrowth = config.playerCharacter.stats.baseAttack;
  const defenseGrowth = config.playerCharacter.stats.baseDefense;
  const levelOffset = Math.max(
    0,
    state.player.level - config.playerCharacter.stats.level.start,
  );
  const weaponBonus =
    state.player.equipment.weapon?.definition.weapon?.attackBonus ?? 0;
  const armorBonus =
    state.player.equipment.armor?.definition.armor?.defenseBonus ?? 0;
  const charmModifiers = equipmentBuffModifiers(state.player.equipment.charms);

  return {
    attack:
      attackGrowth.start +
      Math.floor(levelOffset / attackGrowth.growthEveryLevels) *
        attackGrowth.growthAmount +
      weaponBonus +
      charmModifiers.attack,
    defense:
      defenseGrowth.start +
      Math.floor(levelOffset / defenseGrowth.growthEveryLevels) *
        defenseGrowth.growthAmount +
      armorBonus +
      charmModifiers.defense,
  };
};

const equipmentBuffModifiers = (
  charms: readonly (PlayerItemStack | null)[],
): CombatStats => {
  let attack = 0;
  let defense = 0;

  for (const charm of charms) {
    const effects = charm?.definition.charm?.passive.effects ?? [];

    for (const effect of effects) {
      const modifier = buffModifierFromEffect(effect);

      if (modifier?.stat === "ATK") {
        attack += modifier.magnitude;
      }

      if (modifier?.stat === "DEF") {
        defense += modifier.magnitude;
      }
    }
  }

  return { attack, defense };
};

const applyStatusModifiers = (
  stats: CombatStats,
  statuses: readonly StatusApplication[],
): CombatStats => {
  let attack = stats.attack;
  let defense = stats.defense;

  for (const status of statuses) {
    if (status.status === "shield") {
      defense += config.statusMagnitudes.shieldDefBonus;
    }

    if (status.status === "weaken") {
      attack += config.statusMagnitudes.weakenAtkPenalty;
    }

    const modifier = buffModifierFromRuntimeStatus(status);
    if (modifier?.stat === "ATK") {
      attack += modifier.magnitude;
    }

    if (modifier?.stat === "DEF") {
      defense += modifier.magnitude;
    }
  }

  return { attack, defense };
};

const buffModifierFromEffect = (
  effect: Effect,
): { readonly stat: "ATK" | "DEF"; readonly magnitude: number } | null => {
  if (effect.kind !== "buff_stat" || effect.buffStat === null) {
    return null;
  }

  return {
    stat: effect.buffStat.stat,
    magnitude: effect.buffStat.magnitude,
  };
};

const buffModifierFromRuntimeStatus = (
  status: StatusApplication,
): { readonly stat: "ATK" | "DEF"; readonly magnitude: number } | null => {
  const runtime = status as unknown as {
    readonly kind?: unknown;
    readonly stat?: unknown;
    readonly magnitude?: unknown;
    readonly buffStat?: {
      readonly stat?: unknown;
      readonly magnitude?: unknown;
    };
  };

  if (
    runtime.kind === "buff_stat" &&
    isCombatStat(runtime.stat) &&
    isSafeIntegerNumber(runtime.magnitude)
  ) {
    return {
      stat: runtime.stat,
      magnitude: runtime.magnitude,
    };
  }

  if (
    runtime.buffStat !== undefined &&
    isCombatStat(runtime.buffStat.stat) &&
    isSafeIntegerNumber(runtime.buffStat.magnitude)
  ) {
    return {
      stat: runtime.buffStat.stat,
      magnitude: runtime.buffStat.magnitude,
    };
  }

  return null;
};

const isCombatStat = (value: unknown): value is "ATK" | "DEF" =>
  value === "ATK" || value === "DEF";

const isSafeIntegerNumber = (value: unknown): value is number =>
  typeof value === "number" && Number.isSafeInteger(value);

const combatRngContextFor = (state: GameState): MutableRngContext => {
  const previousDraws = state.rng.streams[COMBAT_RNG_STREAM_ID]?.draws ?? 0;
  const rng = createRng(state.rng.rootSeed);
  const combatRng = rng.fork("combat");

  for (let index = 0; index < previousDraws; index += 1) {
    combatRng.nextUint32();
  }

  return {
    rng: combatRng,
    initialDraws: previousDraws,
    drawsUsed: 0,
  };
};

const withCombatRngCursor = (
  state: GameState,
  context: MutableRngContext,
): GameState => {
  const existing = state.rng.streams[COMBAT_RNG_STREAM_ID];

  return {
    ...state,
    rng: {
      ...state.rng,
      streams: {
        ...state.rng.streams,
        [COMBAT_RNG_STREAM_ID]: {
          streamId: COMBAT_RNG_STREAM_ID,
          seed: existing?.seed ?? state.rng.rootSeed,
          parentStreamId: existing?.parentStreamId ?? ROOT_RNG_STREAM_ID,
          draws: context.initialDraws + context.drawsUsed,
        },
      },
    },
  };
};

const rollInt = (
  context: MutableRngContext,
  min: number,
  max: number,
): number => {
  const range = max - min + 1;
  const limit = UINT32_SIZE - (UINT32_SIZE % range);
  let value = drawUint32(context);

  while (value >= limit) {
    value = drawUint32(context);
  }

  return min + (value % range);
};

const rollVarianceMultiplier = (context: MutableRngContext): number => {
  const unit = drawUint32(context) / UINT32_SIZE;
  const variance = config.combatMath.varianceMultiplier;

  return variance.min + unit * (variance.max - variance.min);
};

const drawUint32 = (context: MutableRngContext): number => {
  context.drawsUsed += 1;

  return context.rng.nextUint32();

    return rejectEffect(
      state,
      effect,
      "bounds",
      `enchant.bonus must be ${bounds.effectVocabulary.verbs.enchant.bonus}`,
      ctx
    );
  }

  const stack = state.player.equipment[target];
  if (stack === null) {
    return invalidTarget(state, effect, ctx, `no ${target} is equipped`);
  }

  const currentBonus = equipmentBonus(stack.definition, target);
  if (currentBonus === null) {
    return invalidTarget(state, effect, ctx, `equipped ${target} is malformed`);
  }

  const maxBonus = enchantRuntimeMax(target);
  const bonusAfter = Math.min(maxBonus, currentBonus + bonus);
  const enchantedStack = withEquipmentBonus(stack, target, bonusAfter);

  return {
    state: {
      ...state,
      player: {
        ...state.player,
        equipment: {
          ...state.player.equipment,
          [target]: enchantedStack
        }
      }
    },
    events: [
      effectExecutedEvent(state, "enchant", ctx, {
        target,
        bonus,
        bonusBefore: currentBonus,
        bonusAfter,
        cap: maxBonus
      })
    ]
  };
}

const resolveHpTarget = (
  state: GameState,
  ctx: EffectExecutionContext
): ActorWithHp | null => {
  const targetId = ctx.targetId ?? ctx.sourceId;
  if (targetId === null) {
    return null;
  }

  if (targetId === "player") {
    return {
      id: "player",
      hpCurrent: state.player.hp.current,
      hpMax: state.player.hp.max
    };
  }

  const entity = state.entities[targetId];
  if (entity?.kind !== "enemy") {
    return null;
  }

  return {
    id: entity.id,
    entity,
    hpCurrent: entity.currentHP,
    hpMax: entity.definition.stats.hp
  };
};

const resolveStatusTargetId = (
  state: GameState,
  ctx: EffectExecutionContext
): StatusEntityId | null => {
  const targetId = ctx.targetId ?? ctx.sourceId;
  if (targetId === null) {
    return null;
  }

  if (targetId === "player") {
    return "player";
  }

  return state.entities[targetId] === undefined ? null : targetId;
};

const withActorHp = (
  state: GameState,
  actor: ActorWithHp,
  current: number
): GameState => {
  if (actor.id === "player") {
    return {
      ...state,
      player: {
        ...state.player,
        hp: {
          ...state.player.hp,
          current
        }
      }
    };
  }

  return {
    ...state,
    entities: {
      ...state.entities,
      [actor.id]: {
        ...actor.entity,
        currentHP: current
      }
    }
  };
};

const statusesForEntity = (
  state: GameState,
  entityId: StatusEntityId
): readonly StatusApplication[] => {
  if (entityId === "player") {
    return state.player.statuses;
  }

  return state.entities[entityId]?.statuses ?? [];
};

const withEntityStatuses = (
  state: GameState,
  entityId: StatusEntityId,
  statuses: readonly StatusApplication[]
): GameState => {
  if (entityId === "player") {
    return {
      ...state,
      player: {
        ...state.player,
        statuses
      }
    };
  }

  const entity = state.entities[entityId];
  if (entity === undefined) {
    return state;
  }

  return {
    ...state,
    entities: {
      ...state.entities,
      [entityId]: {
        ...entity,
        statuses
      } satisfies EntityInstance
    }
  };
};

const appendStatusWithCap = (
  statuses: readonly StatusApplication[],
  status: StatusApplication
): readonly StatusApplication[] => {
  const max = bounds.statusVocabulary.maxConcurrentPerActor;
  const kept = statuses.length >= max ? statuses.slice(1) : statuses;

  return [...kept, status];
};

const runtimeBuffStatus = (input: {
  readonly stat: "ATK" | "DEF";
  readonly magnitude: number;
  readonly duration: number;
}): RuntimeBuffStatus =>
  ({
    status: "buff_stat" as StatusId,
    duration: input.duration,
    kind: "buff_stat",
    stat: input.stat,
    magnitude: input.magnitude
  }) as RuntimeBuffStatus;

type CarriedItemUpdate = {
  readonly matched: boolean;
  readonly stack: PlayerItemStack;
};

const updateCarriedItems = (
  state: GameState,
  update: (stack: PlayerItemStack) => CarriedItemUpdate
): {
  readonly state: GameState;
  readonly matchedCount: number;
  readonly changedCount: number;
} => {
  let matchedCount = 0;
  let changedCount = 0;
  const apply = (stack: PlayerItemStack): PlayerItemStack => {
    const result = update(stack);
    if (result.matched) {
      matchedCount += 1;
    }

    if (result.stack !== stack) {
      changedCount += 1;
    }

    return result.stack;
  };
  const inventory = state.player.inventory.map(
    (slot): InventorySlot => (slot === null ? null : apply(slot))
  );
  const weapon =
    state.player.equipment.weapon === null
      ? null
      : apply(state.player.equipment.weapon);
  const armor =
    state.player.equipment.armor === null
      ? null
      : apply(state.player.equipment.armor);
  const charms = state.player.equipment.charms.map((slot) =>
    slot === null ? null : apply(slot)
  );

  return {
    state: {
      ...state,
      player: {
        ...state.player,
        inventory,
        equipment: {
          weapon,
          armor,
          charms
        }
      }
    },
    matchedCount,
    changedCount
  };
};

const equipmentBonus = (
  definition: ItemDefinition,
  target: "weapon" | "armor"
): number | null => {
  if (target === "weapon") {
    return definition.weapon?.attackBonus ?? null;
  }

  return definition.armor?.defenseBonus ?? null;
};

const withEquipmentBonus = (
  stack: PlayerItemStack,

): TargetingGeometryResult => {
  const cells: Position[] = [];

  for (let y = 0; y < grid.height; y += 1) {
    for (let x = 0; x < grid.width; x += 1) {
      const position = { x, y };

      if (isWalkableTile(getTile(grid, position))) {
        cells.push(position);
      }
    }
  }

  const entityIds = uniqueSortedIds(
    cells.flatMap((cell) => entitiesAt(state, cell))
  );

  return { cells, entityIds };
};

const entitiesAt = (
  state: GameState,
  position: Position
): readonly (EntityId | "player")[] => {
  const ids: (EntityId | "player")[] = [];

  if (samePosition(state.player.position, position)) {
    ids.push("player");
  }

  for (const entity of sortedEntities(state)) {
    if (samePosition(entity.position, position)) {
      ids.push(entity.id);
    }
  }

  return ids;
};

const sortedEntities = (state: GameState): readonly EntityInstance[] =>
  Object.values(state.entities).sort((left, right) =>
    left.id.localeCompare(right.id)
  );

const uniqueSortedIds = (
  ids: readonly (EntityId | "player")[]
): readonly (EntityId | "player")[] => [...new Set(ids)].sort(compareActorId);

const compareActorId = (
  left: EntityId | "player",
  right: EntityId | "player"
): number => {
  if (left === "player") {
    return right === "player" ? 0 : -1;
  }

  if (right === "player") {
    return 1;
  }

  return left.localeCompare(right);
};

const samePosition = (left: Position, right: Position): boolean =>
  left.x === right.x && left.y === right.y;

import { z } from "zod";

import { bounds } from "../../config/index.js";
import { boundedInt, enforceActivePayload, nonEmptyString } from "../common.js";
import { StatusApplicationSchema, STATUS_IDS } from "./statuses.js";

export const EFFECT_VERB_IDS = bounds.effectVocabulary.closedVerbList;

export const EffectVerbKindSchema = z.enum(EFFECT_VERB_IDS);

export type EffectVerbKind = z.infer<typeof EffectVerbKindSchema>;

const CURE_STATUS_TARGETS = [
  ...STATUS_IDS,
  bounds.effectVocabulary.verbs.cureStatus.allKeyword,
] as const;

export const CureStatusTargetSchema = z.enum(CURE_STATUS_TARGETS);

export const BuffStatSchema = z.enum(bounds.effectVocabulary.verbs.buffStat.stats);

export const RevealTargetKindSchema = z.enum(
  bounds.effectVocabulary.verbs.reveal.targetKinds,
);

export const EnchantTargetKindSchema = z.enum(["weapon", "armor"]);

export const IdentifyModeSchema = z.enum(["carried_item", "category"]);

export const EmptyEffectPayloadSchema = z.strictObject({});

export const DamageEffectPayloadSchema = z.strictObject({
  amount: boundedInt(bounds.effectVocabulary.verbs.damage.amount),
});

export const HealEffectPayloadSchema = z.strictObject({
  amount: boundedInt(bounds.effectVocabulary.verbs.heal.amount),
});

export const ApplyStatusEffectPayloadSchema = StatusApplicationSchema;

export const CureStatusEffectPayloadSchema = z.strictObject({
  status: CureStatusTargetSchema,
});

export const BuffStatEffectPayloadSchema = z
  .strictObject({
    stat: BuffStatSchema,
    magnitude: z.number().int(),
    duration: boundedInt(bounds.effectVocabulary.verbs.buffStat.durationTurns),
  })
  .superRefine((payload, ctx) => {
    const magnitudeBounds = bounds.effectVocabulary.verbs.buffStat.magnitudeAbs;
    const absMagnitude = Math.abs(payload.magnitude);

    if (
      absMagnitude < magnitudeBounds.min ||
      absMagnitude > magnitudeBounds.max
    ) {
      ctx.addIssue({
        code: "custom",
        path: ["magnitude"],
        message: `magnitude absolute value must be ${magnitudeBounds.min}-${magnitudeBounds.max}`,
      });
    }
  });

export const NutritionEffectPayloadSchema = z.strictObject({
  fullness: boundedInt(bounds.effectVocabulary.verbs.nutrition.fullness),
});

export const BlinkEffectPayloadSchema = z.strictObject({
  distanceTiles: boundedInt(
    bounds.effectVocabulary.verbs.blink.distanceTiles,
  ),
});

export const KnockbackEffectPayloadSchema = z.strictObject({
  pushTiles: boundedInt(bounds.effectVocabulary.verbs.knockback.pushTiles),
  collisionDamage: boundedInt(
    bounds.effectVocabulary.verbs.knockback.collisionDamage,
  ),
});

export const RevealEffectPayloadSchema = z.strictObject({
  target: RevealTargetKindSchema,
});

export const IdentifyEffectPayloadSchema = z
  .strictObject({
    mode: IdentifyModeSchema,
    carriedItemId: nonEmptyString.nullable(),
    category: nonEmptyString.nullable(),
  })
  .superRefine((payload, ctx) => {
    if (payload.mode === "carried_item" && payload.carriedItemId === null) {
      ctx.addIssue({
        code: "custom",
        path: ["carriedItemId"],
        message: "carried item identify mode requires carriedItemId",
      });
    }

    if (payload.mode === "carried_item" && payload.category !== null) {
      ctx.addIssue({
        code: "custom",
        path: ["category"],
        message: "category must be null for carried item identify mode",
      });
    }

    if (payload.mode === "category" && payload.category === null) {
      ctx.addIssue({
        code: "custom",
        path: ["category"],
        message: "category identify mode requires category",
      });
    }

    if (payload.mode === "category" && payload.carriedItemId !== null) {
      ctx.addIssue({
        code: "custom",
        path: ["carriedItemId"],
        message: "carriedItemId must be null for category identify mode",
      });
    }
  });

export const EnchantEffectPayloadSchema = z.strictObject({
  target: EnchantTargetKindSchema,
  bonus: z.literal(bounds.effectVocabulary.verbs.enchant.bonus),
});

export const SummonEffectPayloadSchema = z.strictObject({
  count: boundedInt(bounds.effectVocabulary.verbs.summon.count),
  rosterEntityId: nonEmptyString,
});

export const TransformEffectPayloadSchema = z.strictObject({
  rosterEntityId: nonEmptyString,
});

export const DigEffectPayloadSchema = z.strictObject({
  lengthTiles: boundedInt(bounds.effectVocabulary.verbs.dig.lengthTiles),
});

const EFFECT_PAYLOAD_KEYS = [
  "damage",
  "heal",
  "applyStatus",
  "cureStatus",
  "buffStat",
  "nutrition",
  "teleportSelf",
  "teleportTarget",
  "blink",
  "knockback",
  "reveal",
  "identify",
  "enchant",
  "summon",
  "transform",
  "dig",
] as const;

const EFFECT_PAYLOAD_FIELD_BY_KIND = {
  damage: "damage",
  heal: "heal",
  apply_status: "applyStatus",
  cure_status: "cureStatus",
  buff_stat: "buffStat",
  nutrition: "nutrition",
  teleport_self: "teleportSelf",
  teleport_target: "teleportTarget",
  blink: "blink",
  knockback: "knockback",
  reveal: "reveal",
  identify: "identify",
  enchant: "enchant",
  summon: "summon",
  transform: "transform",
  dig: "dig",
} as const satisfies Record<EffectVerbKind, (typeof EFFECT_PAYLOAD_KEYS)[number]>;

// Provider-facing: required nullable payload fields avoid a root union.
export const EffectSchema = z
  .strictObject({
    kind: EffectVerbKindSchema,
    damage: DamageEffectPayloadSchema.nullable(),
    heal: HealEffectPayloadSchema.nullable(),
    applyStatus: ApplyStatusEffectPayloadSchema.nullable(),
    cureStatus: CureStatusEffectPayloadSchema.nullable(),
    buffStat: BuffStatEffectPayloadSchema.nullable(),
    nutrition: NutritionEffectPayloadSchema.nullable(),
    teleportSelf: EmptyEffectPayloadSchema.nullable(),
    teleportTarget: EmptyEffectPayloadSchema.nullable(),
    blink: BlinkEffectPayloadSchema.nullable(),
    knockback: KnockbackEffectPayloadSchema.nullable(),
    reveal: RevealEffectPayloadSchema.nullable(),
    identify: IdentifyEffectPayloadSchema.nullable(),
    enchant: EnchantEffectPayloadSchema.nullable(),
    summon: SummonEffectPayloadSchema.nullable(),
    transform: TransformEffectPayloadSchema.nullable(),
    dig: DigEffectPayloadSchema.nullable(),
  })
  .superRefine((effect, ctx) => {
    enforceActivePayload(
      effect,
      ctx,
      EFFECT_PAYLOAD_KEYS,
      EFFECT_PAYLOAD_FIELD_BY_KIND[effect.kind],
    );
  });

export type Effect = z.infer<typeof EffectSchema>;
